window.SITE_LOCALES = {"en":{"lang":"en","meta":{"title":"Not A Translator - Native-language definitions inside the page","description":"Native-language definitions, audio, unit and timezone conversions, smarter lookup routes and console mode for difficult pages."},"shared":{"appName":"Not A Translator","lookup":"Get meaning for","consoleMode":"Console mode","tooltipMode":"Tooltip mode","contribute":"Contribute","dictionary":"Dictionary","badges":{"risky":"risky","conditional":"works under conditions","ok":"ok"},"console":{"copy":"Copy","remove":"Remove","forceForSite":"Force console for this site"},"languages":{"english":"English","spanish":"Spanish","french":"French","german":"German","italian":"Italian","finnish":"Finnish","ancient":"Latin + Greek (translation)"}},"site":{"languageLabel":"Language","brandTagline":"Definitions stay in the text flow.","nav":{"features":"Features","updates":"Updates","engine":"Engine","usage":"Usage","faq":"FAQ"},"hero":{"eyebrow":"Read first. Translate later.","title":"Keep the definition inside the page, in the language that owns the word.","lead":"Not A Translator injects lightweight tooltips near your selection, keeps the original-language definition front and center, and hides a lot of technical work behind a very simple gesture.","primaryCta":"Explore features","secondaryCta":"See the flow","storeCtas":{"install":"Install","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"PayPal Me","paypalLabel":""},"panelNote":"Console mode stores entries when a page resists tooltip rendering.","status":{"published":{"kicker":"Published now","title":"Available on Chrome, Firefox and Firefox Android.","body":"The live application is already distributed on the currently published platforms."},"funding":{"kicker":"Safari track","title":"Safari is being developed, but needs funding to reach publication.","body":"The code path exists, the browser-specific work is real, and funding would help push it to the finish line.","cta":"Support development"}},"points":["Definitions stay in the source language instead of breaking reading with a generic translation detour.","Audio, translate-anyway, repair and open-page actions stay one click away inside the tooltip or console entry.","A lot happens behind the scenes: lookup retries, candidate routing, fallback providers and per-site safeguards."],"inlineDemo":{"before":"Not A Translator injects lightweight ","word":"tooltips","badge":"rotating","definition":"(noun) floating definition boxes that stay close to the selection and can rotate around it to escape edges and overlap.","after":" near your selection, keep the original-language definition front and center, and hide a lot of technical work behind a very simple gesture."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(noun) a long period of time, especially one marked by distinctive events or development."},"signals":{"items":[{"value":"3 published builds","label":"Live today","body":"Chrome, Firefox desktop and Firefox Android are the currently published tracks."},{"value":"Console mode","label":"For difficult pages","body":"When a page fights tooltip rendering, stored definitions move into a controlled side console."},{"value":"Search smarter","label":"Behind the tooltip","body":"Candidate rescue, multi-word lookup and compound handling quietly improve the visible result."}]},"manifesto":{"eyebrow":"Why it feels different","title":"A reading-first workflow.","lead":"The extension is built to keep the page primary: define in place, translate only when needed, and stay readable even when injection gets difficult.","items":[{"title":"Definition before translation","body":"The extension is designed to preserve the idea that a word often makes more sense when its definition comes from its own language first."},{"title":"The page stays the main surface","body":"Tooltip, quick translate, audio and open-page actions stay close to the selection so reading does not immediately turn into tab switching."},{"title":"When a page fights back, the result should survive","body":"Some sites are hostile to inline injections or simply unstable. Console mode exists so the useful part, the stored definition, remains available instead of disappearing with the tooltip."}]},"screenshots":{"eyebrow":"In context","title":"The extension is meant to live inside real reading situations.","lead":"A desktop Firefox view and a mobile Safari development view help make that concrete.","desktop":{"title":"Firefox desktop","body":"Tooltip near the selected word, popup controls, and the original reading flow preserved."},"mobile":{"title":"Safari iPhone development build","body":"A portable layout where the tooltip stays compact and readable inside a mobile page."}},"features":{"eyebrow":"Core features","title":"Simple on the surface, dense underneath.","lead":"One selection can trigger dictionary routing, smarter candidate rescue, audio sourcing, conversion parsing, timezone interpretation and, on hostile pages, a controlled shift into console mode.","items":[{"title":"Native-language definitions","body":"The main path is still the same idea: select a word and get its definition in the language it belongs to, so reading and language learning stay connected."},{"title":"Conversions and timezone helpers","body":"Numeric selections can switch into conversion mode, including unit conversions and timezone-aware time conversion without leaving the page."},{"title":"Audio close to the selection","body":"When pronunciation is available, the tooltip or console entry can expose audio directly, using the best source available for that dictionary."},{"title":"Console mode for hostile pages","body":"The repair action now opens console mode directly. When inline rendering is unreliable, stored entries stay readable in a controlled side panel instead of being lost."},{"title":"Smarter search routes","body":"Lookup now leans on better candidate routing: exact form first, then rescued candidates, multi-word expression handling, and lemma or compound strategies where useful."},{"title":"Lots of technique, quietly","body":"Quick translate now swaps the definition directly inside the tooltip. Behind that are fallback providers, per-site safeguards, mobile positioning work and browser-specific workarounds meant to keep the interaction short."}]},"updates":{"eyebrow":"Recent improvements","title":"Latest work now reflected on the extension site.","lead":"The landing page now describes the current state of the project instead of an older snapshot.","items":[{"kicker":"Conversion","title":"Thousands-aware numeric parsing","body":"Selections such as \"12,333 feet\" and even \"12,333,425 feet\" are now interpreted as grouped thousands instead of decimal numbers."},{"kicker":"Time","title":"Timezone conversion stays part of the same gesture","body":"Time selections can switch to a dedicated tooltip when a timezone is recognized, instead of forcing a separate workflow."},{"kicker":"Dictionary","title":"Finnish joins the active dictionary set","body":"Finnish support is now part of the live lineup, including dictionary access, menu exposure and the related audio / lookup plumbing."},{"kicker":"Lookup","title":"New search paths behind the tooltip","body":"Recent lookup work improves candidate rescue for English multi-word expressions and adds stronger compound handling for Finnish when direct lookup is not enough."}]},"engine":{"eyebrow":"Under the hood","title":"Much more happens than the interface lets on.","lead":"The extension is intentionally light in appearance and busy in the background.","items":[{"title":"Candidate routing","body":"A lookup does not stop at one raw form. The engine can retry exact forms, rescued variants and multi-word candidates before giving up."},{"title":"Conversions that read real text","body":"The conversion path now treats grouped thousands more safely and can switch between unit and timezone interpretation from the same selection."},{"title":"Console fallback","body":"The repair control now acts as a real mode switch: it sends the current lookup into console mode instead of only trying cosmetic recovery."},{"title":"Audio sourcing","body":"Pronunciation can come from Wiktionary, Commons, DWDS or a generated fallback depending on dictionary and availability."},{"title":"Finnish-specific work","body":"Finnish lookup is not just another menu entry: it includes extra dictionary routing and compound-aware strategies behind the scenes."},{"title":"Per-site reliability hints","body":"The badge is there to communicate confidence, not only language. Restricted or hostile pages should not look deceptively safe."},{"title":"Smartphone compatibility","body":"The presentation site now keeps the same hierarchy on small screens: stacked actions, stretch buttons and readable cards instead of a squeezed desktop layout."}]},"usage":{"eyebrow":"Usage","title":"A short gesture that tries to preserve reading.","lead":"The extension tries to keep context, avoid unnecessary navigation and degrade gracefully when a page interferes with injection.","steps":["Select a word or expression in the page you are reading.","Use the extension action or context menu to request the definition.","Read the tooltip near the selection and stay inside the page for definition, audio, quick translate or open-page follow-up.","If site detection proposes console mode, answer OK to switch. You can also click repair, the tool icon inside a tooltip, to send that lookup to the console.","Console mode keeps the stored entries in a stable side panel when inline rendering becomes unreliable.","To set tooltip color and opacity, or disable automatic language detection, open the extension popup: it exposes the current color, the available palette, the opacity slider and the language autodetect switch."]},"platforms":{"title":"Platforms","items":["Published: Firefox desktop","Published: Chrome desktop","Published: Ffox Android","Safari is under active development and needs funding to reach publication."]},"dictionaries":{"title":"Dictionaries","items":["English - Merriam-Webster Learner's Dictionary","Spanish - Diccionario de la Lengua Espa\ufffdf\u00b1ola","French - Larousse","German - DWDS","Italian - De Mauro Internazionale","Finnish - Kielitoimiston sanakirja / Wiktionary fallback","Latin + Greek - translation-oriented ancient-language route"]},"faq":{"eyebrow":"FAQ","title":"A few things worth saying clearly.","items":[{"q":"Is this a machine-translation extension?","a":"No. Translation exists as an optional fallback. The primary idea is still to expose the original-language definition first."},{"q":"Why is console mode important?","a":"Because some pages interfere with inline DOM injections. You can switch to it either by accepting the extension's detection prompt or by clicking repair, the tool icon inside a tooltip. Console mode then keeps the useful part, the stored definitions, even when the page is difficult."},{"q":"Can tooltip appearance be adjusted?","a":"Yes. In the extension popup, you can choose tooltip color, adjust opacity with the dedicated slider, and disable automatic language detection when you prefer to keep control over the active dictionary."},{"q":"Does it do a lot behind the scenes?","a":"Yes, but on purpose. Provider fallback, smarter lookup candidates, audio routing, conversion heuristics and browser-specific workarounds are there so the visible gesture stays simple."},{"q":"Will it work everywhere?","a":"Almost everywhere, but not on browser-restricted pages such as extension stores or other privileged browser surfaces where content scripts are blocked by the browser itself."}]},"footer":"No ads, no trackers, a lot of care, and many browser-specific edge cases handled quietly."}},"fr":{"lang":"fr","meta":{"title":"Not A Translator - D\u00e9finitions en langue d'origine dans la page","description":"D\u00e9finitions en langue source, audio, conversions d'unit\u00e9s et de fuseaux, recherches plus intelligentes et mode console pour les pages difficiles."},"shared":{"appName":"Not A Translator","lookup":"Rechercher le sens de","consoleMode":"Mode console","tooltipMode":"Mode infobulle","contribute":"Contribuer","dictionary":"Dictionnaire","badges":{"risky":"hasardeux","conditional":"sous conditions","ok":"ok"},"console":{"copy":"Copier","remove":"Supprimer","forceForSite":"Forcer la console pour ce site"},"languages":{"english":"Anglais","spanish":"Espagnol","french":"Fran\u00e7ais","german":"Allemand","italian":"Italien","finnish":"Finnois","ancient":"Latin + grec (traduction)"}},"site":{"languageLabel":"Langue","brandTagline":"Les d\u00e9finitions restent dans le flux de lecture.","nav":{"features":"Fonctions","updates":"Nouveaut\u00e9s","engine":"Moteur","usage":"Utilisation","faq":"FAQ"},"hero":{"eyebrow":"Lire d'abord. Traduire ensuite si besoin.","title":"Garder la d\u00e9finition dans la page, dans la langue du mot lui-m\u00eame.","lead":"Not A Translator injecte des infobulles l\u00e9g\u00e8res pr\u00e8s de la s\u00e9lection, met la d\u00e9finition d'origine au premier plan et cache beaucoup de technique derri\u00e8re un geste tr\u00e8s simple.","inlineDemo":{"before":"Not A Translator injecte des ","word":"infobulles","badge":"rotatives","definition":"(nom) bo\u00eetes de d\u00e9finition flottantes qui restent pr\u00e8s de la s\u00e9lection et peuvent tourner autour d'elle pour \u00e9chapper aux bords et aux chevauchements.","after":" l\u00e9g\u00e8res pr\u00e8s de votre s\u00e9lection, gardent la d\u00e9finition dans la langue d'origine au premier plan et cachent beaucoup de technique derri\u00e8re un geste tr\u00e8s simple."},"primaryCta":"Voir les fonctions","secondaryCta":"Voir le parcours","storeCtas":{"install":"Installer","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"PayPal Me","paypalLabel":""},"panelNote":"Le mode console conserve les entr\u00e9es quand une page r\u00e9siste au rendu des infobulles.","status":{"published":{"kicker":"Publi\u00e9 maintenant","title":"Disponible sur Chrome, Firefox et Firefox Android.","body":"L'application vivante est d\u00e9j\u00e0 distribu\u00e9e sur les plateformes actuellement publi\u00e9es."},"funding":{"kicker":"Piste Safari","title":"Safari est en d\u00e9veloppement, mais a besoin de financements pour aller jusqu'\u00e0 la publication.","body":"Le chemin de code existe, le travail sp\u00e9cifique au navigateur est r\u00e9el, et un financement aiderait \u00e0 franchir la derni\u00e8re ligne.","cta":"Soutenir le d\u00e9veloppement"}},"points":["Les d\u00e9finitions restent dans la langue source au lieu de casser la lecture avec un d\u00e9tour de traduction g\u00e9n\u00e9rique.","Audio, traduire quand m\u00eame, r\u00e9paration et ouverture de page restent accessibles directement dans l'infobulle ou l'entr\u00e9e console.","Beaucoup de choses se passent en coulisses : reprises de recherche, routage de candidats, fournisseurs de secours et garde-fous par site."]},"demo":{"word":"epoch","time":"09:58:47","definition":"(nom) longue p\u00e9riode de temps, surtout marqu\u00e9e par des \u00e9v\u00e9nements ou un d\u00e9veloppement particulier."},"signals":{"items":[{"value":"3 builds publi\u00e9s","label":"Disponibles aujourd'hui","body":"Chrome, Firefox desktop et Firefox Android sont les extensions actuellement publi\u00e9es."},{"value":"Mode console","label":"Pour les pages difficiles","body":"Quand une page contrarie le rendu des infobulles, les d\u00e9finitions stock\u00e9es basculent dans une console lat\u00e9rale ma\u00eetris\u00e9e."},{"value":"Recherche plus fine","label":"Derri\u00e8re l'infobulle","body":"Secours de multiples lemmes candidats, fallbacks, expressions multi-mots et gestion des compos\u00e9s am\u00e9liorent discr\u00e8tement le r\u00e9sultat visible."}]},"manifesto":{"eyebrow":"Pourquoi l'exp\u00e9rience diff\u00e8re","title":"Un parcours lecture d'abord.","lead":"L'extension est con\u00e7ue pour laisser la page au centre : d\u00e9finir sur place, traduire seulement si n\u00e9cessaire, et rester lisible m\u00eame quand l'injection devient difficile.","items":[{"title":"La d\u00e9finition avant la traduction","body":"L'extension est pens\u00e9e pour pr\u00e9server l'id\u00e9e qu'un mot se comprend souvent mieux quand sa d\u00e9finition vient d'abord de sa propre langue."},{"title":"La page reste la surface principale","body":"Infobulle, quick translate, audio et ouverture de page restent pr\u00e8s de la s\u00e9lection pour \u00e9viter que la lecture ne se transforme imm\u00e9diatement en navigation entre onglets."},{"title":"Quand la page r\u00e9siste, le r\u00e9sultat doit survivre","body":"Certaines pages sont hostiles aux injections inline ou simplement instables. Le mode console existe pour que l'essentiel, la d\u00e9finition stock\u00e9e, reste disponible au lieu de dispara\u00eetre avec l'infobulle."}]},"screenshots":{"eyebrow":"En situation","title":"L'extension est faite pour vivre dans de vraies situations de lecture.","lead":"Une vue Firefox desktop et une vue Safari iPhone en d\u00e9veloppement rendent cela plus concret.","desktop":{"title":"Firefox desktop","body":"Infobulle pr\u00e8s du mot s\u00e9lectionn\u00e9, contr\u00f4les du popup et flux de lecture d'origine pr\u00e9serv\u00e9."},"mobile":{"title":"Build Safari iPhone en d\u00e9veloppement","body":"Une mise en page portable o\u00f9 l'infobulle reste compacte et lisible \u00e0 l'int\u00e9rieur d'une page mobile."}},"features":{"eyebrow":"Fonctions cl\u00e9s","title":"Simple en surface, dense en profondeur.","lead":"Une seule s\u00e9lection peut d\u00e9clencher du routage de dictionnaires, du secours de candidats, du sourcing audio, du parsing de conversions, de l'interpr\u00e9tation de fuseaux horaires et, sur les pages hostiles, une bascule ma\u00eetris\u00e9e vers le mode console.","items":[{"title":"D\u00e9finitions en langue d'origine","body":"Le principe reste le m\u00eame : s\u00e9lectionner un mot et obtenir sa d\u00e9finition dans sa propre langue, pour garder lecture et apprentissage li\u00e9s."},{"title":"Conversions et fuseaux horaires","body":"Les s\u00e9lections num\u00e9riques peuvent basculer en mode conversion, y compris pour les unit\u00e9s et les heures avec fuseau reconnu, sans quitter la page."},{"title":"Audio au plus pr\u00e8s de la s\u00e9lection","body":"Quand une prononciation existe, l'infobulle ou l'entr\u00e9e console peut l'exposer directement en choisissant la meilleure source disponible."},{"title":"Mode console pour les pages hostiles","body":"Le clic sur l'action repair ouvre maintenant directement le mode console. Quand le rendu inline devient peu fiable, les entr\u00e9es restent lisibles dans un panneau ma\u00eetris\u00e9 au lieu d'\u00eatre perdues."},{"title":"Parcours de recherche plus intelligents","body":"Les recherches s'appuient d\u00e9sormais sur un routage de candidats plus robuste : forme exacte d'abord, puis secours de multiples lemmes candidats, fallbacks, expressions multi-mots et strat\u00e9gies de lemme ou de compos\u00e9 quand c'est utile."},{"title":"Beaucoup de technique, discr\u00e8tement","body":"Quick translate remplace maintenant la d\u00e9finition directement dans l'infobulle. Derri\u00e8re cela se trouvent des fournisseurs de repli, des garde-fous par site, du travail de positionnement mobile et des contournements sp\u00e9cifiques aux navigateurs pour garder un geste court."}]},"updates":{"eyebrow":"Am\u00e9liorations r\u00e9centes","title":"Le site refl\u00e8te maintenant l'\u00e9tat r\u00e9el de l'extension.","lead":"La page de pr\u00e9sentation d\u00e9crit enfin la version actuelle au lieu d'un ancien instantan\u00e9.","items":[{"kicker":"Conversion","title":"Lecture correcte des grands nombres","body":"Des s\u00e9lections comme \u00ab 12,333 feet \u00bb ou m\u00eame \u00ab 12,333,425 feet \u00bb sont maintenant interpr\u00e9t\u00e9es comme des milliers group\u00e9s, et non comme des d\u00e9cimaux."},{"kicker":"Heure","title":"Les fuseaux restent dans le m\u00eame geste","body":"Une s\u00e9lection horaire peut ouvrir une infobulle d\u00e9di\u00e9e quand un fuseau est reconnu, au lieu d'imposer un parcours s\u00e9par\u00e9."},{"kicker":"Dictionnaire","title":"Le finnois rejoint l'ensemble actif","body":"Le finnois fait d\u00e9sormais partie de la gamme vivante, avec dictionnaire, menu, i18n et plomberie audio / recherche associ\u00e9e."},{"kicker":"Recherche","title":"Nouveaux modes de recherche sous le capot","body":"Le travail r\u00e9cent am\u00e9liore le secours sur expressions anglaises multi-mots et ajoute une gestion plus solide des compos\u00e9s finnois quand la recherche directe ne suffit pas."}]},"engine":{"eyebrow":"Sous le capot","title":"Il se passe bien plus de choses que l'interface ne le laisse voir.","lead":"L'extension est volontairement l\u00e9g\u00e8re en apparence et tr\u00e8s active en arri\u00e8re-plan.","items":[{"title":"Routage des candidats","body":"Une recherche ne s'arr\u00eate pas \u00e0 une forme brute. Le moteur peut retenter des formes exactes, des variantes de secours et des candidats multi-mots avant d'abandonner."},{"title":"Conversions qui lisent du vrai texte","body":"Le parcours de conversion traite maintenant plus s\u00fbrement les milliers group\u00e9s et peut arbitrer entre unit\u00e9 et fuseau horaire \u00e0 partir d'une m\u00eame s\u00e9lection."},{"title":"Repli console","body":"Le contr\u00f4le repair agit maintenant comme un vrai changement de mode : il envoie la recherche en cours vers le mode console au lieu d'une simple tentative cosm\u00e9tique."},{"title":"Sourcing audio","body":"La prononciation peut venir de Wiktionary, Commons, DWDS ou d'un secours g\u00e9n\u00e9r\u00e9 selon le dictionnaire et la disponibilit\u00e9."},{"title":"Travail sp\u00e9cifique au finnois","body":"Le finnois n'est pas qu'une entr\u00e9e de menu suppl\u00e9mentaire : il apporte un routage de dictionnaires et des strat\u00e9gies orient\u00e9es compos\u00e9s derri\u00e8re la sc\u00e8ne."},{"title":"Indice de fiabilit\u00e9 par site","body":"La pastille ne sert pas seulement \u00e0 afficher une langue. Elle doit aussi communiquer la confiance, y compris sur les pages restreintes ou hostiles."},{"title":"Compatibilit\u00e9 smartphone","body":"Le site de pr\u00e9sentation garde maintenant la m\u00eame hi\u00e9rarchie sur petit \u00e9cran : actions empil\u00e9es, boutons pleine largeur et cartes lisibles au lieu d'un desktop \u00e9cras\u00e9."}]},"usage":{"eyebrow":"Utilisation","title":"Un geste court qui essaie de pr\u00e9server la lecture.","lead":"L'extension cherche \u00e0 garder le contexte, \u00e0 \u00e9viter les d\u00e9tours inutiles et \u00e0 se d\u00e9grader proprement quand une page perturbe l'injection.","steps":["S\u00e9lectionnez un mot ou une expression dans la page que vous lisez.","Utilisez l'action de l'extension ou le menu contextuel pour demander la d\u00e9finition.","Lisez l'infobulle pr\u00e8s de la s\u00e9lection et restez dans la page pour la d\u00e9finition, l'audio, quick translate ou l'ouverture de page si besoin.","Si la d\u00e9tection du site vous propose le mode console, r\u00e9pondez OK pour y basculer. Vous pouvez aussi cliquer sur repair, l'ic\u00f4ne outil dans un tooltip, pour envoyer cette recherche vers la console.","Le mode console conserve les entr\u00e9es stock\u00e9es dans un panneau lat\u00e9ral stable quand le rendu inline devient peu fiable.","Pour r\u00e9gler la couleur et l'opacit\u00e9 des tooltips, ou d\u00e9sactiver la d\u00e9tection automatique de langue, ouvrez le popup de l'extension : vous y trouverez la couleur courante, la palette disponible, le curseur d'opacit\u00e9 et le commutateur de d\u00e9tection de langue."]},"platforms":{"title":"Plateformes","items":["Publi\u00e9 : Firefox desktop","Publi\u00e9 : Chrome desktop","Publi\u00e9 : Ffox Android","Safari est en d\u00e9veloppement actif et a besoin de financements pour aller jusqu'\u00e0 la publication."]},"dictionaries":{"title":"Dictionnaires","items":["Anglais - Merriam-Webster Learner's Dictionary","Espagnol - Diccionario de la Lengua Espa\u00f1ola","Fran\u00e7ais - Larousse","Allemand - DWDS","Italien - De Mauro Internazionale","Finnois - Kielitoimiston sanakirja avec repli Wiktionary","Latin + grec - parcours orient\u00e9 traduction pour les langues anciennes"]},"faq":{"eyebrow":"FAQ","title":"Quelques points \u00e0 dire clairement.","items":[{"q":"Est-ce une extension de traduction automatique ?","a":"Non. La traduction existe en secours facultatif. L'id\u00e9e principale reste d'exposer d'abord la d\u00e9finition en langue d'origine."},{"q":"Pourquoi le mode console est-il important ?","a":"Parce que certaines pages perturbent les injections inline dans le DOM. Vous pouvez y basculer soit en acceptant la d\u00e9tection propos\u00e9e par l'extension, soit en cliquant sur repair, l'ic\u00f4ne outil dans un tooltip. Le mode console conserve alors la partie utile, les d\u00e9finitions stock\u00e9es, m\u00eame quand la page est difficile."},{"q":"Peut-on r\u00e9gler l'apparence des tooltips ?","a":"Oui. Dans le popup de l'extension, vous pouvez choisir la couleur des tooltips, ajuster leur opacit\u00e9 avec le curseur pr\u00e9vu pour cela et d\u00e9sactiver la d\u00e9tection automatique de langue si vous pr\u00e9f\u00e9rez garder la main sur le dictionnaire actif."},{"q":"Y a-t-il beaucoup de technique derri\u00e8re ?","a":"Oui, volontairement. Fournisseurs de repli, candidats de recherche plus intelligents, routage audio, heuristiques de conversion et contournements sp\u00e9cifiques aux navigateurs servent \u00e0 garder le geste visible tr\u00e8s simple."},{"q":"Est-ce que cela fonctionne partout ?","a":"Presque partout, mais pas sur les pages restreintes par le navigateur lui-m\u00eame, par exemple les stores d'extensions ou d'autres surfaces privil\u00e9gi\u00e9es o\u00f9 les content scripts sont bloqu\u00e9s."}]},"footer":"Pas de pubs, pas de traceurs, beaucoup de soin, et une grande quantit\u00e9 de cas limites navigateur g\u00e9r\u00e9s discr\u00e8tement."}},"es":{"lang":"es","meta":{"title":"Not A Translator - Definiciones en el idioma original dentro de la p\u00e1gina","description":"Definiciones en la lengua de origen, audio, conversiones de unidades y zonas horarias, b\u00fasquedas m\u00e1s inteligentes y modo consola para p\u00e1ginas dif\u00edciles."},"shared":{"appName":"Not A Translator","lookup":"Obtener significado para","consoleMode":"Modo consola","tooltipMode":"Modo tooltip","contribute":"Contribuir","dictionary":"Diccionario","badges":{"risky":"arriesgado","conditional":"funciona bajo condiciones","ok":"ok"},"console":{"copy":"Copiar","remove":"Eliminar","forceForSite":"Forzar la consola para este sitio"},"languages":{"english":"Ingl\u00e9s","spanish":"Espa\u00f1ol","french":"Franc\u00e9s","german":"Alem\u00e1n","italian":"Italiano","finnish":"Finland\u00e9s","ancient":"Lat\u00edn + griego (traducci\u00f3n)"}},"site":{"languageLabel":"Idioma","brandTagline":"Las definiciones permanecen dentro del flujo de lectura.","nav":{"features":"Funciones","updates":"Novedades","engine":"Motor","usage":"Uso","faq":"FAQ"},"hero":{"eyebrow":"Leer primero. Traducir despu\u00e9s si hace falta.","title":"Mantener la definici\u00f3n dentro de la p\u00e1gina, en la lengua que le pertenece a la palabra.","lead":"Not A Translator inyecta tooltips ligeros cerca de la selecci\u00f3n, deja la definici\u00f3n original en primer plano y esconde mucha t\u00e9cnica detr\u00e1s de un gesto muy simple.","primaryCta":"Ver funciones","secondaryCta":"Ver el flujo","storeCtas":{"install":"Instalar","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"Contribuir","paypalLabel":"PayPal"},"panelNote":"El modo consola conserva las entradas cuando una p\u00e1gina se resiste al renderizado inline.","status":{"published":{"kicker":"Publicado ahora","title":"Disponible en Chrome, Firefox y Firefox Android.","body":"La aplicaci\u00f3n viva ya se distribuye en las plataformas actualmente publicadas."},"funding":{"kicker":"Ruta Safari","title":"Safari est\u00e1 en desarrollo, pero necesita financiaci\u00f3n para llegar a publicarse.","body":"La ruta de c\u00f3digo existe, el trabajo espec\u00edfico del navegador es real y la financiaci\u00f3n ayudar\u00eda a cruzar la \u00faltima etapa.","cta":"Apoyar el desarrollo"}},"points":["Las definiciones permanecen en la lengua de origen en lugar de romper la lectura con un desv\u00edo gen\u00e9rico de traducci\u00f3n.","Audio, traducir de todos modos, reparaci\u00f3n y apertura de p\u00e1gina siguen disponibles dentro del tooltip o de la entrada de consola.","Detr\u00e1s hay mucho trabajo: reintentos de b\u00fasqueda, rutas de candidatos, proveedores de reserva y salvaguardas por sitio."],"inlineDemo":{"before":"Not A Translator inyecta ","word":"tooltips","badge":"rotativos","definition":"(sust.) cuadros de definici\u00f3n flotantes que permanecen cerca de la selecci\u00f3n y pueden girar a su alrededor para escapar de los bordes y los solapamientos.","after":" ligeros cerca de su selecci\u00f3n, mantienen la definici\u00f3n en el idioma original en primer plano y esconden mucha t\u00e9cnica detr\u00e1s de un gesto muy simple."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(sust.) periodo largo de tiempo, especialmente marcado por acontecimientos o un desarrollo particular."},"signals":{"items":[{"value":"3 builds publicados","label":"Disponibles hoy","body":"Chrome, Firefox desktop y Firefox Android son las rutas actualmente publicadas."},{"value":"Modo consola","label":"Para p\u00e1ginas dif\u00edciles","body":"Cuando una p\u00e1gina complica el renderizado del tooltip, las definiciones almacenadas pasan a una consola lateral controlada."},{"value":"B\u00fasqueda m\u00e1s fina","label":"Detr\u00e1s del tooltip","body":"Rescate de candidatos, expresiones de varias palabras y manejo de compuestos mejoran discretamente el resultado visible."}]},"manifesto":{"eyebrow":"Por qu\u00e9 se siente distinto","title":"No es un flujo traducci\u00f3n primero. Es un flujo lectura primero.","lead":"La web hace ahora expl\u00edcita esa filosof\u00eda en lugar de dejarla escondida entre notas t\u00e9cnicas.","items":[{"title":"La definici\u00f3n antes que la traducci\u00f3n","body":"La extensi\u00f3n est\u00e1 dise\u00f1ada para preservar la idea de que una palabra suele entenderse mejor cuando la definici\u00f3n llega primero desde su propia lengua."},{"title":"Publicado donde ya importa","body":"El producto ya est\u00e1 vivo en Chrome, Firefox desktop y Firefox Android, as\u00ed que el relato p\u00fablico debe decirlo con claridad."},{"title":"Safari es una ruta seria, no una promesa decorativa","body":"El soporte para Safari se est\u00e1 desarrollando de verdad, pero el acabado espec\u00edfico del navegador todav\u00eda necesita financiaci\u00f3n dedicada."}]},"screenshots":{"eyebrow":"En situaci\u00f3n","title":"La extensi\u00f3n est\u00e1 pensada para vivir dentro de situaciones reales de lectura.","lead":"Una vista Firefox desktop y una vista Safari iPhone en desarrollo ayudan a volver eso concreto.","desktop":{"title":"Firefox desktop","body":"Tooltip cerca de la palabra seleccionada, controles del popup y el flujo de lectura original conservado."},"mobile":{"title":"Build Safari iPhone en desarrollo","body":"Una disposici\u00f3n port\u00e1til donde el tooltip sigue siendo compacto y legible dentro de una p\u00e1gina m\u00f3vil."}},"features":{"eyebrow":"Funciones clave","title":"Simple en uso, t\u00e9cnico en segundo plano.","lead":"La interacci\u00f3n visible es m\u00ednima. La maquinaria invisible no lo es.","items":[{"title":"Definiciones en la lengua original","body":"La idea principal sigue siendo la misma: seleccionar una palabra y obtener su definici\u00f3n en su propia lengua para mantener unidas la lectura y el aprendizaje."},{"title":"Conversiones y zonas horarias","body":"Las selecciones num\u00e9ricas pueden pasar al modo conversi\u00f3n, incluidas unidades y horas con zona horaria reconocida, sin salir de la p\u00e1gina."},{"title":"Audio cerca de la selecci\u00f3n","body":"Cuando existe pronunciaci\u00f3n, el tooltip o la entrada de consola puede exponer audio directamente usando la mejor fuente disponible."},{"title":"Modo consola para p\u00e1ginas hostiles","body":"El clic en repair abre ahora directamente el modo consola. Cuando el renderizado inline no es fiable, las entradas siguen siendo legibles en un panel controlado en vez de perderse."},{"title":"Rutas de b\u00fasqueda m\u00e1s inteligentes","body":"Las b\u00fasquedas ahora dependen de un enrutado de candidatos m\u00e1s robusto: forma exacta primero, luego rescates, expresiones de varias palabras y estrategias de lema o compuesto cuando conviene."},{"title":"Mucha t\u00e9cnica, discretamente","body":"Quick translate ahora sustituye la definici\u00f3n directamente dentro del tooltip. Proxys de traducci\u00f3n, reservas, ajustes m\u00f3viles y protecciones por sitio mantienen ese flujo compacto."}]},"updates":{"eyebrow":"Mejoras recientes","title":"La web ya refleja el estado real de la extensi\u00f3n.","lead":"La p\u00e1gina de presentaci\u00f3n describe por fin la versi\u00f3n actual en lugar de una instant\u00e1nea antigua.","items":[{"kicker":"Conversi\u00f3n","title":"Lectura correcta de n\u00fameros grandes","body":"Selecciones como \u201c12,333 feet\u201d e incluso \u201c12,333,425 feet\u201d se interpretan ahora como miles agrupados y no como n\u00fameros decimales."},{"kicker":"Hora","title":"Las zonas horarias siguen formando parte del mismo gesto","body":"Una selecci\u00f3n horaria puede abrir un tooltip dedicado cuando se reconoce una zona horaria, en lugar de obligar a un flujo aparte."},{"kicker":"Diccionario","title":"El fin\u00e9s entra en el conjunto activo","body":"El fin\u00e9s ya forma parte de la l\u00ednea viva, con diccionario, men\u00fa, i18n y la fontaner\u00eda de audio / b\u00fasqueda asociada."},{"kicker":"B\u00fasqueda","title":"Nuevos modos de b\u00fasqueda bajo el cap\u00f3","body":"El trabajo reciente mejora el rescate de expresiones inglesas de varias palabras y a\u00f1ade un manejo m\u00e1s s\u00f3lido de compuestos finlandeses cuando la b\u00fasqueda directa no basta."}]},"engine":{"eyebrow":"Bajo el cap\u00f3","title":"Suceden muchas m\u00e1s cosas de las que deja ver la interfaz.","lead":"La extensi\u00f3n es deliberadamente ligera en apariencia y muy activa en segundo plano.","items":[{"title":"Enrutado de candidatos","body":"Una b\u00fasqueda no se detiene en una sola forma bruta. El motor puede reintentar formas exactas, variantes de rescate y candidatos de varias palabras antes de rendirse."},{"title":"Conversiones que leen texto real","body":"La ruta de conversi\u00f3n trata ahora con m\u00e1s seguridad los miles agrupados y puede decidir entre unidad y zona horaria a partir de la misma selecci\u00f3n."},{"title":"Reserva en consola","body":"El control repair act\u00faa ahora como un verdadero cambio de modo: env\u00eda la b\u00fasqueda actual al modo consola en lugar de limitarse a una recuperaci\u00f3n cosm\u00e9tica."},{"title":"Suministro de audio","body":"La pronunciaci\u00f3n puede venir de Wiktionary, Commons, DWDS o de una reserva generada seg\u00fan diccionario y disponibilidad."},{"title":"Trabajo espec\u00edfico para fin\u00e9s","body":"El fin\u00e9s no es solo otra entrada de men\u00fa: a\u00f1ade enrutado de diccionarios y estrategias de compuestos detr\u00e1s del tel\u00f3n."},{"title":"Pista de fiabilidad por sitio","body":"El badge no est\u00e1 solo para mostrar una lengua. Tambi\u00e9n debe comunicar confianza, incluso en p\u00e1ginas restringidas u hostiles."},{"title":"Compatibilidad smartphone","body":"La web de presentaci\u00f3n mantiene ahora la misma jerarqu\u00eda en pantallas peque\u00f1as: acciones apiladas, botones a lo ancho y tarjetas legibles en lugar de un escritorio comprimido."}]},"usage":{"eyebrow":"Uso","title":"Un gesto corto que intenta preservar la lectura.","lead":"La extensi\u00f3n intenta mantener el contexto, evitar navegaci\u00f3n innecesaria y degradarse con elegancia cuando una p\u00e1gina interfiere con la inyecci\u00f3n.","steps":["Seleccione una palabra o una expresi\u00f3n en la p\u00e1gina que est\u00e1 leyendo.","Use la acci\u00f3n de la extensi\u00f3n o el men\u00fa contextual para pedir la definici\u00f3n.","Lea el tooltip junto a la selecci\u00f3n y permanezca dentro de la p\u00e1gina para la definici\u00f3n, el audio, quick translate o la apertura de p\u00e1gina si hace falta.","Si la detecci\u00f3n del sitio propone el modo consola, responda OK para cambiar. Tambi\u00e9n puede hacer clic en repair, el icono de herramienta dentro de un tooltip, para enviar esa b\u00fasqueda a la consola.","El modo consola conserva las entradas almacenadas en un panel lateral estable cuando el renderizado inline se vuelve poco fiable.","Para ajustar el color y la opacidad de los tooltips, o desactivar la detecci\u00f3n autom\u00e1tica del idioma, abra el popup de la extensi\u00f3n: all\u00ed est\u00e1n el color actual, la paleta disponible, el control deslizante de opacidad y el interruptor de autodetecci\u00f3n de idioma."]},"platforms":{"title":"Plataformas","items":["Publicado: Firefox desktop","Publicado: Chrome desktop","Publicado: Firefox Android","Safari est\u00e1 en desarrollo activo y necesita financiaci\u00f3n para llegar a la publicaci\u00f3n."]},"dictionaries":{"title":"Diccionarios","items":["Ingl\u00e9s - Merriam-Webster Learner's Dictionary","Espa\u00f1ol - Diccionario de la Lengua Espa\u00f1ola","Franc\u00e9s - Larousse","Alem\u00e1n - DWDS","Italiano - De Mauro Internazionale","Fin\u00e9s - Kielitoimiston sanakirja con reserva en Wiktionary","Lat\u00edn + griego - ruta orientada a traducci\u00f3n para lenguas antiguas"]},"faq":{"eyebrow":"FAQ","title":"Algunas cosas que conviene decir con claridad.","items":[{"q":"\u00bfEs una extensi\u00f3n de traducci\u00f3n autom\u00e1tica?","a":"No. La traducci\u00f3n existe como recurso opcional. La idea principal sigue siendo mostrar primero la definici\u00f3n en la lengua original."},{"q":"\u00bfPor qu\u00e9 es importante el modo consola?","a":"Porque algunas p\u00e1ginas interfieren con las inyecciones inline en el DOM. Puede entrar aceptando la detecci\u00f3n propuesta por la extensi\u00f3n o haciendo clic en repair, el icono de herramienta dentro de un tooltip. El modo consola conserva la parte \u00fatil, las definiciones almacenadas, incluso cuando la p\u00e1gina es dif\u00edcil."},{"q":"\u00bfSe puede ajustar el aspecto de los tooltips?","a":"S\u00ed. En el popup de la extensi\u00f3n puede elegir el color de los tooltips, ajustar la opacidad con el control deslizante dedicado y desactivar la detecci\u00f3n autom\u00e1tica del idioma si prefiere mantener el control sobre el diccionario activo."},{"q":"\u00bfHay mucha t\u00e9cnica detr\u00e1s?","a":"S\u00ed, a prop\u00f3sito. Proveedores de reserva, candidatos de b\u00fasqueda m\u00e1s inteligentes, rutas de audio, heur\u00edsticas de conversi\u00f3n y soluciones espec\u00edficas del navegador sirven para mantener el gesto visible muy simple."},{"q":"\u00bfFunciona en todas partes?","a":"Casi en todas partes, pero no en p\u00e1ginas restringidas por el propio navegador, por ejemplo las tiendas de extensiones u otras superficies privilegiadas donde los content scripts est\u00e1n bloqueados."}]},"footer":"Sin anuncios, sin rastreadores, con mucho cuidado, y con una gran cantidad de casos l\u00edmite del navegador resueltos discretamente."}},"de":{"lang":"de","meta":{"title":"Not A Translator - Definitionen in der Ursprungssprache direkt auf der Seite","description":"Definitionen in der Ursprungssprache, Audio, Einheiten- und Zeitzonen-Umrechnungen, intelligentere Suchpfade und Konsolenmodus f\u00fcr schwierige Seiten."},"shared":{"appName":"Not A Translator","lookup":"Bedeutung suchen f\u00fcr","consoleMode":"Konsolenmodus","tooltipMode":"Tooltip-Modus","contribute":"Beitragen","dictionary":"W\u00f6rterbuch","badges":{"risky":"riskant","conditional":"funktioniert unter Bedingungen","ok":"ok"},"console":{"copy":"Kopieren","remove":"Entfernen","forceForSite":"Konsolenmodus f\u00fcr diese Seite erzwingen"},"languages":{"english":"Englisch","spanish":"Spanisch","french":"Franz\u00f6sisch","german":"Deutsch","italian":"Italienisch","finnish":"Finnisch","ancient":"Latein + Griechisch (\ufffdobersetzung)"}},"site":{"languageLabel":"Sprache","brandTagline":"Definitionen bleiben im Lesefluss.","nav":{"features":"Funktionen","updates":"Neuheiten","engine":"Engine","usage":"Verwendung","faq":"FAQ"},"hero":{"eyebrow":"Erst lesen. Dann \u00fcbersetzen, wenn n\u00f6tig.","title":"Die Definition auf der Seite behalten, in der Sprache, zu der das Wort geh\u00f6rt.","lead":"Not A Translator f\u00fcgt leichte Tooltips nahe an Ihrer Auswahl ein, h\u00e4lt die Definition in der Ursprungssprache im Vordergrund und versteckt viel Technik hinter einer sehr einfachen Geste.","primaryCta":"Funktionen ansehen","secondaryCta":"Ablauf ansehen","storeCtas":{"install":"Installieren","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"PayPal Me","paypalLabel":""},"panelNote":"Der Konsolenmodus bewahrt Eintr\u00e4ge, wenn eine Seite das Tooltip-Rendering st\u00f6rt.","status":{"published":{"kicker":"Jetzt ver\u00f6ffentlicht","title":"Verf\u00fcgbar f\u00fcr Chrome, Firefox und Firefox Android.","body":"Die lebendige Anwendung wird bereits auf den derzeit ver\u00f6ffentlichten Plattformen verteilt."},"funding":{"kicker":"Safari-Spur","title":"Safari ist in Entwicklung, braucht aber Finanzierung bis zur Ver\u00f6ffentlichung.","body":"Der Codepfad existiert, die browserspezifische Arbeit ist real, und Finanzierung w\u00fcrde helfen, die letzte Strecke zu schaffen.","cta":"Entwicklung unterst\u00fctzen"}},"points":["Definitionen bleiben in der Ausgangssprache, statt das Lesen mit einem allgemeinen \ufffdobersetzungsumweg zu unterbrechen.","Audio, trotzdem \u00fcbersetzen, Reparatur und Seiten\u00f6ffnung bleiben direkt im Tooltip oder im Konsoleneintrag erreichbar.","Hinter den Kulissen passiert viel: Suchwiederholungen, Kandidaten-Routing, Fallback-Anbieter und Schutzmechanismen pro Website."],"inlineDemo":{"before":"Not A Translator f\ufffdgt leichte ","word":"Tooltips","badge":"rotierend","definition":"(Subst.) schwebende Definitionsfelder, die nahe an der Auswahl bleiben und sich um sie drehen k\ufffdnnen, um R\ufffdndern und \ufffdberlappungen auszuweichen.","after":" nahe an Ihrer Auswahl ein, halten die Definition in der Ursprungssprache im Vordergrund und verstecken viel Technik hinter einer sehr einfachen Geste."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(Subst.) ein langer Zeitraum, besonders einer, der durch bestimmte Ereignisse oder Entwicklungen gepr\u00e4gt ist."},"signals":{"items":[{"value":"3 ver\u00f6ffentlichte Builds","label":"Heute verf\u00fcgbar","body":"Chrome, Firefox Desktop und Firefox Android sind die derzeit ver\u00f6ffentlichten Erweiterungen."},{"value":"Konsolenmodus","label":"F\u00fcr schwierige Seiten","body":"Wenn eine Seite das Tooltip-Rendering st\u00f6rt, wechseln gespeicherte Definitionen in eine kontrollierte Seitenkonsole."},{"value":"Intelligentere Suche","label":"Hinter dem Tooltip","body":"Kandidatenrettung, Mehrwortsuche und Kompositabehandlung verbessern unauff\u00e4llig das sichtbare Ergebnis."}]},"manifesto":{"eyebrow":"Warum es sich anders anf\u00fchlt","title":"Ein Lesen-zuerst-Ablauf.","lead":"Die Erweiterung ist darauf ausgelegt, die Seite im Mittelpunkt zu lassen: direkt auf der Seite definieren, nur bei Bedarf \u00fcbersetzen und lesbar bleiben, auch wenn die Injection schwierig wird.","items":[{"title":"Definition vor \ufffdobersetzung","body":"Die Erweiterung soll die Idee bewahren, dass ein Wort oft besser verstanden wird, wenn seine Definition zuerst aus seiner eigenen Sprache kommt."},{"title":"Die Seite bleibt die Hauptfl\u00e4che","body":"Tooltip, Quick Translate, Audio und Seiten\u00f6ffnung bleiben nahe an der Auswahl, damit Lesen nicht sofort zu Tab-Wechseln wird."},{"title":"Wenn die Seite sich wehrt, muss das Ergebnis \u00fcberleben","body":"Manche Seiten sind feindlich gegen\u00fcber Inline-Injections oder schlicht instabil. Der Konsolenmodus sorgt daf\u00fcr, dass der n\u00fctzliche Teil, die gespeicherte Definition, verf\u00fcgbar bleibt, statt mit dem Tooltip zu verschwinden."}]},"screenshots":{"eyebrow":"Im Einsatz","title":"Die Erweiterung ist daf\u00fcr gemacht, in echten Lesesituationen zu leben.","lead":"Eine Firefox-Desktop-Ansicht und eine Safari-iPhone-Entwicklungsansicht machen das greifbarer.","desktop":{"title":"Firefox Desktop","body":"Tooltip nahe am ausgew\u00e4hlten Wort, Popup-Steuerung und urspr\u00fcnglicher Lesefluss bleiben erhalten."},"mobile":{"title":"Safari iPhone Entwicklungs-Build","body":"Ein mobiles Layout, in dem der Tooltip kompakt und lesbar innerhalb einer mobilen Seite bleibt."}},"features":{"eyebrow":"Kernfunktionen","title":"An der Oberfl\u00e4che einfach, darunter dicht.","lead":"Eine einzige Auswahl kann W\u00f6rterbuch-Routing, intelligentere Kandidatenrettung, Audioquellen, Umrechnungs-Parsing, Zeitzonen-Interpretation und auf feindlichen Seiten einen kontrollierten Wechsel in den Konsolenmodus ausl\u00f6sen.","items":[{"title":"Definitionen in der Ursprungssprache","body":"Der Hauptpfad bleibt dieselbe Idee: ein Wort ausw\u00e4hlen und seine Definition in der Sprache erhalten, zu der es geh\u00f6rt, damit Lesen und Sprachenlernen verbunden bleiben."},{"title":"Umrechnungen und Zeitzonenhilfen","body":"Numerische Auswahlen k\u00f6nnen in den Umrechnungsmodus wechseln, einschlie\ufffdYlich Einheiten und zeitzonenbezogener Uhrzeiten, ohne die Seite zu verlassen."},{"title":"Audio nahe an der Auswahl","body":"Wenn eine Aussprache verf\u00fcgbar ist, kann der Tooltip oder der Konsoleneintrag Audio direkt bereitstellen, mit der jeweils besten Quelle f\u00fcr dieses W\u00f6rterbuch."},{"title":"Konsolenmodus f\u00fcr feindliche Seiten","body":"Die Aktion repair \u00f6ffnet jetzt direkt den Konsolenmodus. Wenn Inline-Rendering unzuverl\u00e4ssig wird, bleiben gespeicherte Eintr\u00e4ge in einem kontrollierten Seitenpanel lesbar, statt verloren zu gehen."},{"title":"Intelligentere Suchpfade","body":"Die Suche st\u00fctzt sich jetzt auf robusteres Kandidaten-Routing: zuerst die exakte Form, dann gerettete Kandidaten, Mehrwortausdr\u00fccke sowie Lemma- oder Kompositastrategien, wenn sie n\u00fctzlich sind."},{"title":"Viel Technik, leise","body":"Quick Translate ersetzt jetzt die Definition direkt im Tooltip. Dahinter stehen Fallback-Anbieter, Schutzmechanismen pro Website, mobile Positionierungsarbeit und browserspezifische Workarounds, damit die Interaktion kurz bleibt."}]},"updates":{"eyebrow":"J\u00fcngste Verbesserungen","title":"Die Website spiegelt jetzt den realen Stand der Erweiterung wider.","lead":"Die Pr\u00e4sentationsseite beschreibt endlich die aktuelle Version statt eines \u00e4lteren Schnappschusses.","items":[{"kicker":"Umrechnung","title":"Korrekte Auswertung gro\ufffdYer Zahlen","body":"Auswahlen wie \ufffd?z12,333 feet\ufffd?o oder sogar \ufffd?z12,333,425 feet\ufffd?o werden jetzt als Tausendergruppen statt als Dezimalzahlen interpretiert."},{"kicker":"Zeit","title":"Zeitzonen bleiben Teil derselben Geste","body":"Eine Uhrzeit-Auswahl kann ein eigenes Tooltip \u00f6ffnen, wenn eine Zeitzone erkannt wird, statt einen getrennten Ablauf zu erzwingen."},{"kicker":"W\u00f6rterbuch","title":"Finnisch geh\u00f6rt jetzt zum aktiven Satz","body":"Finnisch ist jetzt Teil der lebendigen Auswahl, mit W\u00f6rterbuchzugang, Men\u00fceintr\u00e4gen sowie der zugeh\u00f6rigen Audio- und Suchlogik."},{"kicker":"Suche","title":"Neue Suchpfade unter dem Tooltip","body":"Neuere Sucharbeit verbessert die Kandidatenrettung f\u00fcr englische Mehrwortausdr\u00fccke und st\u00e4rkt die Kompositabehandlung f\u00fcr Finnisch, wenn die Direktsuche nicht reicht."}]},"engine":{"eyebrow":"Unter der Haube","title":"Es passiert viel mehr, als die Oberfl\u00e4che erkennen l\u00e4sst.","lead":"Die Erweiterung wirkt absichtlich leicht und ist im Hintergrund sehr aktiv.","items":[{"title":"Kandidaten-Routing","body":"Eine Suche endet nicht bei einer rohen Form. Die Engine kann exakte Formen, gerettete Varianten und Mehrwortkandidaten erneut versuchen, bevor sie aufgibt."},{"title":"Umrechnungen, die echten Text lesen","body":"Der Umrechnungspfad behandelt Tausendergruppen jetzt sicherer und kann aus derselben Auswahl zwischen Einheit und Zeitzone unterscheiden."},{"title":"Konsolen-Fallback","body":"Die repair-Steuerung wirkt jetzt wie ein echter Moduswechsel: Sie schickt die aktuelle Suche in den Konsolenmodus statt nur eine kosmetische Reparatur zu versuchen."},{"title":"Audioquellen","body":"Aussprache kann je nach W\u00f6rterbuch und Verf\u00fcgbarkeit aus Wiktionary, Commons, DWDS oder einem generierten Fallback kommen."},{"title":"Finnisch-spezifische Arbeit","body":"Finnisch ist nicht nur ein weiterer Men\u00fceintrag: Dahinter stehen eigenes W\u00f6rterbuch-Routing und kompositaorientierte Strategien."},{"title":"Hinweise zur Zuverl\u00e4ssigkeit pro Website","body":"Das Badge soll nicht nur Sprache anzeigen. Es soll auch Vertrauen vermitteln, auch auf eingeschr\u00e4nkten oder feindlichen Seiten."},{"title":"Smartphone-Kompatibilit\u00e4t","body":"Die Pr\u00e4sentationsseite beh\u00e4lt jetzt dieselbe Hierarchie auf kleinen Bildschirmen: gestapelte Aktionen, Buttons \u00fcber die volle Breite und lesbare Karten statt einer gequetschten Desktop-Ansicht."}]},"usage":{"eyebrow":"Verwendung","title":"Eine kurze Geste, die das Lesen bewahren will.","lead":"Die Erweiterung versucht, den Kontext zu erhalten, unn\u00f6tige Navigation zu vermeiden und sich sauber zur\u00fcckzunehmen, wenn eine Seite die Injection st\u00f6rt.","steps":["W\u00e4hlen Sie ein Wort oder einen Ausdruck auf der Seite aus, die Sie gerade lesen.","Nutzen Sie die Aktion der Erweiterung oder das Kontextmen\u00fc, um die Definition anzufordern.","Lesen Sie den Tooltip nahe an der Auswahl und bleiben Sie f\u00fcr Definition, Audio, Quick Translate oder das \ufffd-ffnen der Seite in der Seite.","Wenn die Website-Erkennung den Konsolenmodus vorschl\u00e4gt, antworten Sie mit OK, um zu wechseln. Sie k\u00f6nnen auch auf repair, das Werkzeugsymbol im Tooltip, klicken, um diese Suche in die Konsole zu schicken.","Der Konsolenmodus h\u00e4lt gespeicherte Eintr\u00e4ge in einem stabilen Seitenpanel, wenn Inline-Rendering unzuverl\u00e4ssig wird.","Um Tooltip-Farbe und Opazit\u00e4t einzustellen oder die automatische Spracherkennung zu deaktivieren, \u00f6ffnen Sie das Popup der Erweiterung: Dort finden Sie die aktuelle Farbe, die verf\u00fcgbare Palette, den Opazit\u00e4tsregler und den Schalter f\u00fcr die Sprachautodetektion."]},"platforms":{"title":"Plattformen","items":["Ver\u00f6ffentlicht: Firefox Desktop","Ver\u00f6ffentlicht: Chrome Desktop","Ver\u00f6ffentlicht: Firefox Android","Safari befindet sich in aktiver Entwicklung und braucht Finanzierung bis zur Ver\u00f6ffentlichung."]},"dictionaries":{"title":"W\u00f6rterb\u00fccher","items":["Englisch - Merriam-Webster Learner's Dictionary","Spanisch - Diccionario de la Lengua Espa\u00f1ola","Franz\u00f6sisch - Larousse","Deutsch - DWDS","Italienisch - De Mauro Internazionale","Finnisch - Kielitoimiston sanakirja / Wiktionary-Fallback","Latein + Griechisch - \u00fcbersetzungsorientierter Pfad f\u00fcr antike Sprachen"]},"faq":{"eyebrow":"FAQ","title":"Ein paar Dinge, die klar gesagt werden sollten.","items":[{"q":"Ist das eine maschinelle \ufffdobersetzungserweiterung?","a":"Nein. \ufffdobersetzung existiert als optionaler R\u00fcckweg. Die Hauptidee bleibt, zuerst die Definition in der Ursprungssprache zu zeigen."},{"q":"Warum ist der Konsolenmodus wichtig?","a":"Weil manche Seiten Inline-DOM-Injections st\u00f6ren. Sie k\u00f6nnen entweder \u00fcber den von der Erweiterung vorgeschlagenen Hinweis dorthin wechseln oder auf repair, das Werkzeugsymbol im Tooltip, klicken. Der Konsolenmodus bewahrt dann den n\u00fctzlichen Teil, die gespeicherten Definitionen, auch wenn die Seite schwierig ist."},{"q":"Kann man das Aussehen der Tooltips anpassen?","a":"Ja. Im Popup der Erweiterung k\u00f6nnen Sie die Farbe der Tooltips w\u00e4hlen, ihre Opazit\u00e4t mit dem vorgesehenen Regler anpassen und die automatische Spracherkennung deaktivieren, wenn Sie das aktive W\u00f6rterbuch lieber selbst steuern m\u00f6chten."},{"q":"Passiert im Hintergrund viel Technik?","a":"Ja, absichtlich. Fallback-Anbieter, intelligentere Suchkandidaten, Audio-Routing, Umrechnungsheuristiken und browserspezifische Workarounds sorgen daf\u00fcr, dass die sichtbare Geste einfach bleibt."},{"q":"Funktioniert das \u00fcberall?","a":"Fast \u00fcberall, aber nicht auf Seiten, die vom Browser selbst eingeschr\u00e4nkt werden, etwa Erweiterungs-Stores oder andere privilegierte Fl\u00e4chen, auf denen Content-Skripte blockiert sind."}]},"footer":"Keine Werbung, keine Tracker, viel Sorgfalt und viele browser-spezifische Grenzf\u00e4lle, die leise abgefangen werden."}},"fi":{"lang":"fi","meta":{"title":"Not A Translator - M\u00e4\u00e4ritelm\u00e4t alkuper\u00e4iskielell\u00e4 suoraan sivulla","description":"Alkuper\u00e4iskieliset m\u00e4\u00e4ritelm\u00e4t, \u00e4\u00e4ni, yksikk\u00f6- ja aikavy\u00f6hykemuunnokset, \u00e4lykk\u00e4\u00e4mm\u00e4t haut ja konsolitila vaikeille sivuille."},"shared":{"appName":"Not A Translator","lookup":"Hae sanan merkitys","consoleMode":"Konsolitila","tooltipMode":"Ty\u00f6kaluvihjetila","contribute":"Osallistu","dictionary":"Sanakirja","badges":{"risky":"riskialtis","conditional":"toimii tietyiss\u00e4 oloissa","ok":"ok"},"console":{"copy":"Kopioi","remove":"Poista","forceForSite":"Pakota konsoli t\u00e4lle sivustolle"},"languages":{"english":"Englanti","spanish":"Espanja","french":"Ranska","german":"Saksa","italian":"Italia","finnish":"Suomi","ancient":"Latina + kreikka (k\u00e4\u00e4nn\u00f6s)"}},"site":{"languageLabel":"Kieli","brandTagline":"M\u00e4\u00e4ritelm\u00e4t pysyv\u00e4t lukemisen virrassa.","nav":{"features":"Ominaisuudet","updates":"Uutta","engine":"Moottori","usage":"K\u00e4ytt\u00f6","faq":"UKK"},"hero":{"eyebrow":"Lue ensin. K\u00e4\u00e4nn\u00f6 vasta tarvittaessa.","title":"Pid\u00e4 m\u00e4\u00e4ritelm\u00e4 sivulla, sill\u00e4 kielell\u00e4 jolle sana kuuluu.","lead":"Not A Translator lis\u00e4\u00e4 kevyet ty\u00f6kaluvihjeet valinnan l\u00e4helle, nostaa alkuper\u00e4iskielisen m\u00e4\u00e4ritelm\u00e4n etusijalle ja piilottaa paljon tekniikkaa hyvin yksinkertaisen eleen taakse.","primaryCta":"Tutki ominaisuuksia","secondaryCta":"Katso ty\u00f6nkulku","storeCtas":{"install":"Asenna","chrome":"Chrome","firefoxAndroid":"Firefox Android","firefox":"Firefox","paypal":"Osallistu","paypalLabel":"PayPal"},"panelNote":"Konsolitila s\u00e4ilytt\u00e4\u00e4 merkinn\u00e4t, kun sivu vastustaa ty\u00f6kaluvihjeiden render\u00f6inti\u00e4.","status":{"published":{"kicker":"Julkaistu nyt","title":"Saatavilla Chromelle, Firefoxille ja Firefox Androidille.","body":"El\u00e4v\u00e4 sovellus on jo julkaistu t\u00e4ll\u00e4 hetkell\u00e4 julkaistuilla alustoilla."},"funding":{"kicker":"Safari-rata","title":"Safari on kehityksess\u00e4, mutta tarvitsee rahoitusta julkaisuun asti.","body":"Koodipolku on olemassa, selainkohtainen ty\u00f6 on todellista, ja rahoitus auttaisi viem\u00e4\u00e4n sen maaliin.","cta":"Tue kehityst\u00e4"}},"points":["M\u00e4\u00e4ritelm\u00e4t pysyv\u00e4t l\u00e4hdekielell\u00e4 sen sijaan, ett\u00e4 lukeminen katkeaisi yleiseen k\u00e4\u00e4nn\u00f6skierrokseen.","\u00c4\u00e4ni, k\u00e4\u00e4nn\u00e4 silti, korjaus ja sivun avaus pysyv\u00e4t yhden napsautuksen p\u00e4\u00e4ss\u00e4 ty\u00f6kaluvihjeess\u00e4 tai konsolimerkinn\u00e4ss\u00e4.","Kulissien takana tapahtuu paljon: hakujen uusintayrityksi\u00e4, ehdokasreitityst\u00e4, varapalveluja ja sivustokohtaisia suojauksia."],"inlineDemo":{"before":"Not A Translator lis\u00e4\u00e4 kevyet ","word":"tooltipit","badge":"kiertyv\u00e4t","definition":"(subst.) kelluvat m\u00e4\u00e4ritelm\u00e4laatikot, jotka pysyv\u00e4t valinnan l\u00e4hell\u00e4 ja voivat kiert\u00e4\u00e4 sen ymp\u00e4ri v\u00e4ist\u00e4\u00e4kseen reunoja ja p\u00e4\u00e4llekk\u00e4isyyksi\u00e4.","after":" valinnan l\u00e4helle, pit\u00e4v\u00e4t alkuper\u00e4iskielisen m\u00e4\u00e4ritelm\u00e4n etualalla ja piilottavat paljon tekniikkaa hyvin yksinkertaisen eleen taakse."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(subst.) pitk\u00e4 ajanjakso, jota leimaavat tietyt tapahtumat tai kehitys."},"signals":{"items":[{"value":"3 julkaistua buildi\u00e4","label":"Saatavilla nyt","body":"Chrome, Firefox desktop ja Firefox Android ovat t\u00e4ll\u00e4 hetkell\u00e4 julkaistut radat."},{"value":"Konsolitila","label":"Vaikeille sivuille","body":"Kun sivu sotkee ty\u00f6kaluvihjeen render\u00f6inti\u00e4, tallennetut m\u00e4\u00e4ritelm\u00e4t siirtyv\u00e4t hallittuun sivukonsoliin."},{"value":"\u00c4lykk\u00e4\u00e4mpi haku","label":"Ty\u00f6kaluvihjeen takana","body":"Ehdokkaiden pelastusreitit, monisanaiset haut ja yhdysrakenteiden k\u00e4sittely parantavat n\u00e4kyv\u00e4\u00e4 tulosta hiljaa."}]},"manifesto":{"eyebrow":"Miksi t\u00e4m\u00e4 tuntuu erilaiselta","title":"Ei k\u00e4\u00e4nn\u00f6s ensin -ty\u00f6nkulku. Vaan luku ensin -ty\u00f6nkulku.","lead":"Sivusto tekee nyt t\u00e4m\u00e4n filosofian n\u00e4kyv\u00e4ksi sen sijaan, ett\u00e4 se j\u00e4isi teknisten huomioiden v\u00e4liin.","items":[{"title":"M\u00e4\u00e4ritelm\u00e4 ennen k\u00e4\u00e4nn\u00f6st\u00e4","body":"Laajennus on rakennettu s\u00e4ilytt\u00e4m\u00e4\u00e4n ajatus siit\u00e4, ett\u00e4 sana ymm\u00e4rret\u00e4\u00e4n usein paremmin, kun m\u00e4\u00e4ritelm\u00e4 tulee ensin sen omasta kielest\u00e4."},{"title":"Julkaistu siell\u00e4 miss\u00e4 sill\u00e4 jo on merkityst\u00e4","body":"Tuote on jo julkaistu Chromelle, Firefox desktopille ja Firefox Androidille, joten julkisen esittelyn pit\u00e4\u00e4 sanoa se selv\u00e4sti."},{"title":"Safari on vakava rata, ei koristeellinen lupaus","body":"Safari-tukea kehitet\u00e4\u00e4n oikeasti, mutta selainkohtainen viimeistely tarvitsee edelleen omaa rahoitustaan."}]},"screenshots":{"eyebrow":"K\u00e4yt\u00e4nn\u00f6ss\u00e4","title":"Laajennus on tarkoitettu el\u00e4m\u00e4\u00e4n aidoissa lukutilanteissa.","lead":"Firefox desktop -n\u00e4kym\u00e4 ja Safari iPhone -kehitysn\u00e4kym\u00e4 tekev\u00e4t siit\u00e4 konkreettisen.","desktop":{"title":"Firefox desktop","body":"Ty\u00f6kaluvihje valitun sanan l\u00e4hell\u00e4, popup-ohjaimet ja alkuper\u00e4inen lukemisen virta s\u00e4ilyv\u00e4t."},"mobile":{"title":"Safari iPhone -kehitysversio","body":"Kannettava asettelu, jossa ty\u00f6kaluvihje pysyy kompaktina ja luettavana mobiilisivun sis\u00e4ll\u00e4."}},"features":{"eyebrow":"Ydinominaisuudet","title":"K\u00e4yt\u00f6ss\u00e4 yksinkertainen, taustalla tekninen.","lead":"N\u00e4kyv\u00e4 vuorovaikutus on pieni. N\u00e4kym\u00e4t\u00f6n koneisto ei ole.","items":[{"title":"Alkuper\u00e4iskieliset m\u00e4\u00e4ritelm\u00e4t","body":"P\u00e4\u00e4ajatus on edelleen sama: valitse sana ja saat sen m\u00e4\u00e4ritelm\u00e4n sen omalla kielell\u00e4, jotta lukeminen ja oppiminen pysyv\u00e4t yhdess\u00e4."},{"title":"Muunnokset ja aikavy\u00f6hykkeet","body":"Numeerinen valinta voi vaihtua muunnostilaan, mukaan lukien yksik\u00f6t ja tunnistetut aikavy\u00f6hykkeet, ilman ett\u00e4 poistut sivulta."},{"title":"\u00c4\u00e4ni valinnan l\u00e4hell\u00e4","body":"Kun \u00e4\u00e4nt\u00e4mys on saatavilla, ty\u00f6kaluvihje tai konsolimerkint\u00e4 voi tarjota sen suoraan k\u00e4ytt\u00e4en parasta saatavilla olevaa l\u00e4hdett\u00e4."},{"title":"Konsolitila vaikeille sivuille","body":"Repair-toiminnon napsautus avaa nyt suoraan konsolitilan. Kun inline-render\u00f6inti ei ole luotettava, merkinn\u00e4t pysyv\u00e4t luettavina hallitussa paneelissa katoamisen sijaan."},{"title":"\u00c4lykk\u00e4\u00e4mm\u00e4t hakureitit","body":"Haku nojaa nyt vahvempaan ehdokasreititykseen: tarkka muoto ensin, sitten pelastusreitit, monisanaiset ilmaukset sek\u00e4 lemma- ja yhdysstrategiat siell\u00e4 miss\u00e4 niist\u00e4 on hy\u00f6ty\u00e4."},{"title":"Paljon tekniikkaa, hiljaa","body":"Quick translate vaihtaa nyt m\u00e4\u00e4ritelm\u00e4n suoraan ty\u00f6kaluvihjeen sis\u00e4ll\u00e4. K\u00e4\u00e4nn\u00f6sproxyt, varapalvelut, mobiilisijoittelu ja sivustokohtaiset suojaukset pit\u00e4v\u00e4t t\u00e4m\u00e4n virtauksen kompaktina."}]},"updates":{"eyebrow":"Viimeaikaiset parannukset","title":"Sivusto kuvaa nyt laajennuksen todellista nykytilaa.","lead":"Esittelysivu kertoo viimein nykyisest\u00e4 versiosta eik\u00e4 vanhasta tilannekuvasta.","items":[{"kicker":"Muunnos","title":"Suurten lukujen oikea tulkinta","body":"Valinnat kuten \"12,333 feet\" ja jopa \"12,333,425 feet\" tulkitaan nyt tuhaterottimiksi eik\u00e4 desimaaliluvuiksi."},{"kicker":"Aika","title":"Aikavy\u00f6hyke pysyy samassa eleess\u00e4","body":"Aikavalinta voi avata oman ty\u00f6kaluvihjeens\u00e4, kun aikavy\u00f6hyke tunnistetaan, sen sijaan ett\u00e4 tarvittaisiin erillinen ty\u00f6nkulku."},{"kicker":"Sanakirja","title":"Suomi liittyy aktiiviseen valikoimaan","body":"Suomi kuuluu nyt el\u00e4v\u00e4\u00e4n sanakirjaryhm\u00e4\u00e4n menuineen, i18n-tukineen sek\u00e4 siihen liittyvine \u00e4\u00e4ni- ja hakureitteineen."},{"kicker":"Haku","title":"Uusia hakutapoja konepellin alla","body":"Viimeaikainen ty\u00f6 parantaa englannin monisanaisten ilmausten pelastusreittej\u00e4 ja lis\u00e4\u00e4 vahvemman yhdysrakenteiden k\u00e4sittelyn suomelle, kun suora haku ei riit\u00e4."}]},"engine":{"eyebrow":"Konepellin alla","title":"Paljon enemm\u00e4n tapahtuu kuin k\u00e4ytt\u00f6liittym\u00e4 n\u00e4ytt\u00e4\u00e4.","lead":"Laajennus on tarkoituksella kevyt ulosp\u00e4in ja kiireinen taustalla.","items":[{"title":"Ehdokasreititys","body":"Haku ei pys\u00e4hdy yhteen raakamuotoon. Moottori voi yritt\u00e4\u00e4 tarkkoja muotoja, pelastusvariantteja ja monisanaisia ehdokkaita ennen luovuttamista."},{"title":"Muunnokset, jotka lukevat oikeaa teksti\u00e4","body":"Muunnosreitti k\u00e4sittelee nyt turvallisemmin tuhaterottimet ja voi erottaa yksik\u00f6n ja aikavy\u00f6hykkeen samasta valinnasta."},{"title":"Konsolivara","body":"Repair-ohjain toimii nyt oikeana tilanvaihtona: se l\u00e4hett\u00e4\u00e4 nykyisen haun konsolitilaan pelk\u00e4n kosmeettisen korjauksen sijaan."},{"title":"\u00c4\u00e4nil\u00e4hteet","body":"\u00c4\u00e4nt\u00e4mys voi tulla Wiktionaryst\u00e4, Commonsista, DWDS:st\u00e4 tai luodusta varal\u00e4hteest\u00e4 sanakirjan ja saatavuuden mukaan."},{"title":"Suomikohtainen ty\u00f6","body":"Suomi ei ole vain yksi valikkorivi lis\u00e4\u00e4: taustalla on omaa sanakirjareitityst\u00e4 ja yhdysstrategioita."},{"title":"Sivukohtainen luotettavuusvihje","body":"Badgen teht\u00e4v\u00e4 ei ole vain n\u00e4ytt\u00e4\u00e4 kielt\u00e4. Sen pit\u00e4\u00e4 viesti\u00e4 my\u00f6s luotettavuudesta, my\u00f6s rajoitetuilla tai hankalilla sivuilla."},{"title":"\u00c4lypuhelinyhteensopivuus","body":"Esittelysivusto s\u00e4ilytt\u00e4\u00e4 nyt saman hierarkian pienill\u00e4 n\u00e4yt\u00f6ill\u00e4: pinotut toiminnot, t\u00e4ysleve\u00e4t painikkeet ja luettavat kortit puristetun desktop-n\u00e4kym\u00e4n sijaan."}]},"usage":{"eyebrow":"K\u00e4ytt\u00f6","title":"Lyhyt ele, joka yritt\u00e4\u00e4 s\u00e4ilytt\u00e4\u00e4 lukemisen.","lead":"Laajennus yritt\u00e4\u00e4 s\u00e4ilytt\u00e4\u00e4 kontekstin, v\u00e4ltt\u00e4\u00e4 turhaa siirtyily\u00e4 ja heikenty\u00e4 hallitusti, kun sivu h\u00e4iritsee injektiota.","steps":["Valitse sana tai ilmaus lukemaltasi sivulta.","Pyyd\u00e4 m\u00e4\u00e4ritelm\u00e4 laajennuksen toiminnolla tai kontekstivalikosta.","Lue ty\u00f6kaluvihje valinnan vierest\u00e4 ja pysy sivulla m\u00e4\u00e4ritelm\u00e4n, \u00e4\u00e4nen, quick translaten tai sivun avauksen kanssa tarvittaessa.","Jos sivuston tunnistus ehdottaa konsolitilaa, vastaa OK vaihtaaksesi siihen. Voit my\u00f6s napsauttaa repair-kuvaketta, ty\u00f6kalukuvaketta tooltipissa, l\u00e4hett\u00e4\u00e4ksesi haun konsoliin.","Konsolitila s\u00e4ilytt\u00e4\u00e4 tallennetut merkinn\u00e4t vakaassa sivupaneelissa, kun inline-render\u00f6inti muuttuu ep\u00e4luotettavaksi.","Tooltipien v\u00e4ri\u00e4 ja opasiteettia s\u00e4\u00e4det\u00e4\u00e4n laajennuksen popupista. Samasta paikasta voit my\u00f6s poistaa automaattisen kielentunnistuksen k\u00e4yt\u00f6st\u00e4: siell\u00e4 n\u00e4kyv\u00e4t nykyinen v\u00e4ri, k\u00e4ytett\u00e4viss\u00e4 oleva paletti, opasiteettiliukus\u00e4\u00e4din ja kielentunnistuksen kytkin."]},"platforms":{"title":"Alustat","items":["Julkaistu: Firefox desktop","Julkaistu: Chrome desktop","Julkaistu: Firefox Android","Safari on aktiivisessa kehityksess\u00e4 ja tarvitsee rahoitusta julkaisuun asti."]},"dictionaries":{"title":"Sanakirjat","items":["Englanti - Merriam-Webster Learner's Dictionary","Espanja - Diccionario de la Lengua Espa\u00f1ola","Ranska - Larousse","Saksa - DWDS","Italia - De Mauro Internazionale","Suomi - Kielitoimiston sanakirja ja Wiktionary-varareitti","Latina + kreikka - k\u00e4\u00e4nn\u00f6spainotteinen reitti antiikin kielille"]},"faq":{"eyebrow":"UKK","title":"Muutama asia on hyv\u00e4 sanoa suoraan.","items":[{"q":"Onko t\u00e4m\u00e4 konek\u00e4\u00e4nn\u00f6slaajennus?","a":"Ei. K\u00e4\u00e4nn\u00f6s on valinnainen varareitti. P\u00e4\u00e4ajatus on edelleen n\u00e4ytt\u00e4\u00e4 ensin alkuper\u00e4iskielinen m\u00e4\u00e4ritelm\u00e4."},{"q":"Miksi konsolitila on t\u00e4rke\u00e4\u00e4","a":"Koska jotkin sivut h\u00e4iritsev\u00e4t inline-DOM-injektioita. Voit siirty\u00e4 siihen joko hyv\u00e4ksym\u00e4ll\u00e4 laajennuksen ehdottaman tunnistuksen tai napsauttamalla repair-kuvaketta tooltipissa. Konsolitila s\u00e4ilytt\u00e4\u00e4 silloin hy\u00f6dyllisen osan, tallennetut m\u00e4\u00e4ritelm\u00e4t, vaikka sivu olisi vaikea."},{"q":"Voiko tooltipien ulkoasua s\u00e4\u00e4t\u00e4\u00e4?","a":"Kyll\u00e4. Laajennuksen popupissa voit valita tooltipien v\u00e4rin, s\u00e4\u00e4t\u00e4\u00e4 opasiteettia omalla liukus\u00e4\u00e4timell\u00e4\u00e4n ja poistaa automaattisen kielentunnistuksen k\u00e4yt\u00f6st\u00e4, jos haluat pit\u00e4\u00e4 aktiivisen sanakirjan itse hallinnassa."},{"q":"Onko taustalla paljon tekniikkaa?","a":"Kyll\u00e4, tarkoituksella. Varapalvelut, \u00e4lykk\u00e4\u00e4mm\u00e4t hakuehdokkaat, \u00e4\u00e4nireititys, muunnosheuristiikat ja selainkohtaiset kiertotavat pit\u00e4v\u00e4t n\u00e4kyv\u00e4n eleen silti yksinkertaisena."},{"q":"Toimiiko t\u00e4m\u00e4 kaikkialla?","a":"L\u00e4hes kaikkialla, mutta ei selaimen itsens\u00e4 rajoittamilla sivuilla, kuten lis\u00e4osakaupoissa tai muissa etuoikeutetuissa n\u00e4kymiss\u00e4, joissa sis\u00e4lt\u00f6skriptit on estetty."}]},"footer":"Ei mainoksia, ei seurantaa, paljon huolellisuutta, ja suuri m\u00e4\u00e4r\u00e4 selainkohtaisia reunatapauksia hoidettuna hiljaa."}}};
